import static org.junit.jupiter.api.Assertions.*;

class TaskTest {

    private static Validator validator;

    @BeforeAll
    static void setUpValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    // --- Field access and defaults ---

    @Test
    void shouldCreateTaskWithAllFields() {
        Task task = new Task();
        task.setTitle("Test Task");
        task.setDescription("A description");
        task.setCreatedBy(1L);

        assertEquals("Test Task", task.getTitle());
        assertEquals("A description", task.getDescription());
        assertEquals(1L, task.getCreatedBy());
    }

    @Test
    void shouldHaveNullIdBeforePersistence() {
        Task task = new Task();
        assertNull(task.getId());
    }

    @Test
    void shouldHaveNullCreatedAtBeforePersistence() {
        Task task = new Task();
        assertNull(task.getCreatedAt());
    }

    @Test
    void shouldHaveNullUpdatedAtByDefault() {
        Task task = new Task();
        assertNull(task.getUpdatedAt());
    }

    @Test
    void shouldHaveDeletedFalseByDefault() {
        Task task = new Task();
        assertFalse(task.isDeleted(), "deleted should default to false");
    }

    @Test
    void shouldSetAndGetDeletedField() {
        Task task = new Task();
        task.setDeleted(true);
        assertTrue(task.isDeleted());
    }

    // --- Priority enum ---

    @Test
    void priorityEnumShouldHaveThreeValues() {
        Task.Priority[] values = Task.Priority.values();
        assertEquals(3, values.length);
    }

    @Test
    void priorityEnumShouldContainHighMediumLow() {
        assertNotNull(Task.Priority.valueOf("HIGH"));
        assertNotNull(Task.Priority.valueOf("MEDIUM"));
        assertNotNull(Task.Priority.valueOf("LOW"));
    }

    @Test
    void shouldDefaultPriorityToMedium() {
        Task task = new Task();
        assertEquals(Task.Priority.MEDIUM, task.getPriority(),
                "Default priority should be MEDIUM");
    }

    @Test
    void shouldSetAndGetPriority() {
        Task task = new Task();
        task.setPriority(Task.Priority.HIGH);
        assertEquals(Task.Priority.HIGH, task.getPriority());

        task.setPriority(Task.Priority.LOW);
        assertEquals(Task.Priority.LOW, task.getPriority());
    }

    // --- TaskStatus enum ---

    @Test
    void taskStatusEnumShouldHaveFourValues() {
        Task.TaskStatus[] values = Task.TaskStatus.values();
        assertEquals(4, values.length);
    }

    @Test
    void taskStatusEnumShouldContainAllStates() {
        assertNotNull(Task.TaskStatus.valueOf("TODO"));
        assertNotNull(Task.TaskStatus.valueOf("IN_PROGRESS"));
        assertNotNull(Task.TaskStatus.valueOf("DONE"));
        assertNotNull(Task.TaskStatus.valueOf("CLOSED"));
    }

    @Test
    void shouldDefaultStatusToTodo() {
        Task task = new Task();
        assertEquals(Task.TaskStatus.TODO, task.getStatus(),
                "Default status should be TODO");
    }

    @Test
    void shouldSetAndGetStatus() {
        Task task = new Task();
        task.setStatus(Task.TaskStatus.IN_PROGRESS);
        assertEquals(Task.TaskStatus.IN_PROGRESS, task.getStatus());
    }

    // --- Title validation (M2-AC3, AC15: 1-200 chars) ---

    @Test
    void shouldRejectNullTitle() {
        Task task = createValidTask();
        task.setTitle(null);

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertTrue(hasTitleViolation, "Null title should be rejected");
    }

    @Test
    void shouldRejectEmptyTitle() {
        Task task = createValidTask();
        task.setTitle("");

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertTrue(hasTitleViolation, "Empty title should be rejected");
    }

    @Test
    void shouldAcceptTitleWith1Character() {
        Task task = createValidTask();
        task.setTitle("A");

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertFalse(hasTitleViolation, "Title with 1 char should be accepted");
    }

    @Test
    void shouldAcceptTitleWith200Characters() {
        Task task = createValidTask();
        task.setTitle("a".repeat(200));

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertFalse(hasTitleViolation, "Title with 200 chars should be accepted");
    }

    @Test
    void shouldRejectTitleWith201Characters() {
        Task task = createValidTask();
        task.setTitle("a".repeat(201));

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertTrue(hasTitleViolation, "Title with 201 chars should be rejected");
    }

    // --- Description validation (M2-AC16: max 5000 chars) ---

    @Test
    void shouldAcceptNullDescription() {
        Task task = createValidTask();
        task.setDescription(null);

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasDescViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("description"));
        assertFalse(hasDescViolation, "Null description should be accepted");
    }

    @Test
    void shouldAcceptDescriptionWith5000Characters() {
        Task task = createValidTask();
        task.setDescription("a".repeat(5000));

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasDescViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("description"));
        assertFalse(hasDescViolation, "Description with 5000 chars should be accepted");
    }

    @Test
    void shouldRejectDescriptionWith5001Characters() {
        Task task = createValidTask();
        task.setDescription("a".repeat(5001));

        Set<ConstraintViolation<Task>> violations = validator.validate(task);
        boolean hasDescViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("description"));
        assertTrue(hasDescViolation, "Description with 5001 chars should be rejected");
    }

    // --- Helper ---

    private Task createValidTask() {
        Task task = new Task();
        task.setTitle("Valid Title");
        task.setDescription("Valid description");
        task.setCreatedBy(1L);
        return task;
    }
}

