package com.taskflow.repository;

import com.taskflow.entity.Task;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;

@DataJpaTest
class TaskRepositoryTest {

    @Autowired
    private TestEntityManager entityManager;

    @Autowired
    private TaskRepository taskRepository;

    // --- Helper ---

    private Task createAndPersistTask(String title, Task.Priority priority, Task.TaskStatus status, boolean deleted) {
        Task task = new Task();
        task.setTitle(title);
        task.setDescription("Description for " + title);
        task.setPriority(priority);
        task.setStatus(status);
        task.setCreatedBy(1L);
        task.setDeleted(deleted);
        entityManager.persistAndFlush(task);
        return task;
    }

    private Task createAndPersistTask(String title) {
        return createAndPersistTask(title, Task.Priority.MEDIUM, Task.TaskStatus.TODO, false);
    }

    // --- CRUD basics ---

    @Test
    void shouldAutoGenerateId() {
        Task saved = createAndPersistTask("Auto ID Task");
        assertNotNull(saved.getId());
    }

    @Test
    void shouldSetCreatedAtAutomatically() {
        Task saved = createAndPersistTask("CreatedAt Task");
        assertNotNull(saved.getCreatedAt(), "createdAt should be set by @PrePersist");
    }

    @Test
    void shouldPersistAllFields() {
        Task task = new Task();
        task.setTitle("Full Task");
        task.setDescription("Full description");
        task.setPriority(Task.Priority.HIGH);
        task.setStatus(Task.TaskStatus.IN_PROGRESS);
        task.setCreatedBy(42L);
        entityManager.persistAndFlush(task);

        Task found = entityManager.find(Task.class, task.getId());
        assertEquals("Full Task", found.getTitle());
        assertEquals("Full description", found.getDescription());
        assertEquals(Task.Priority.HIGH, found.getPriority());
        assertEquals(Task.TaskStatus.IN_PROGRESS, found.getStatus());
        assertEquals(42L, found.getCreatedBy());
        assertNotNull(found.getCreatedAt());
        assertFalse(found.isDeleted());
    }

    @Test
    void shouldDefaultPriorityToMedium() {
        Task task = new Task();
        task.setTitle("Default Priority");
        task.setCreatedBy(1L);
        entityManager.persistAndFlush(task);

        Task found = entityManager.find(Task.class, task.getId());
        assertEquals(Task.Priority.MEDIUM, found.getPriority());
    }

    @Test
    void shouldDefaultStatusToTodo() {
        Task task = new Task();
        task.setTitle("Default Status");
        task.setCreatedBy(1L);
        entityManager.persistAndFlush(task);

        Task found = entityManager.find(Task.class, task.getId());
        assertEquals(Task.TaskStatus.TODO, found.getStatus());
    }

    // --- findByIdAndDeletedFalse (M2-AC9) ---

    @Test
    void findByIdAndDeletedFalse_shouldReturnActiveTask() {
        Task saved = createAndPersistTask("Active Task");

        Optional<Task> found = taskRepository.findByIdAndDeletedFalse(saved.getId());

        assertTrue(found.isPresent());
        assertEquals("Active Task", found.get().getTitle());
    }

    @Test
    void findByIdAndDeletedFalse_shouldNotReturnSoftDeletedTask() {
        Task saved = createAndPersistTask("Deleted Task", Task.Priority.MEDIUM, Task.TaskStatus.TODO, true);

        Optional<Task> found = taskRepository.findByIdAndDeletedFalse(saved.getId());

        assertFalse(found.isPresent(), "Soft-deleted task should not be found");
    }

    @Test
    void findByIdAndDeletedFalse_shouldReturnEmptyForNonExistentId() {
        Optional<Task> found = taskRepository.findByIdAndDeletedFalse(99999L);

        assertFalse(found.isPresent());
    }

    // --- Pageable search/filter queries (M2-AC8,10,11,12) ---

    @Test
    void searchTasks_shouldExcludeSoftDeletedTasks() {
        createAndPersistTask("Active One");
        createAndPersistTask("Deleted One", Task.Priority.MEDIUM, Task.TaskStatus.TODO, true);

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters(null, null, null, pageable);

        assertEquals(1, page.getTotalElements(), "Soft-deleted tasks should be excluded");
        assertEquals("Active One", page.getContent().get(0).getTitle());
    }

    @Test
    void searchTasks_shouldReturnAllActiveTasksWithNoFilters() {
        createAndPersistTask("Task A");
        createAndPersistTask("Task B");
        createAndPersistTask("Task C");

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters(null, null, null, pageable);

        assertEquals(3, page.getTotalElements());
    }

    @Test
    void searchTasks_shouldFilterByKeywordCaseInsensitive() {
        createAndPersistTask("Important Task");
        createAndPersistTask("Another Item");
        createAndPersistTask("IMPORTANT ITEM");

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters("important", null, null, pageable);

        assertEquals(2, page.getTotalElements(), "Should match case-insensitively");
    }

    @Test
    void searchTasks_shouldFilterByPriority() {
        createAndPersistTask("High Task", Task.Priority.HIGH, Task.TaskStatus.TODO, false);
        createAndPersistTask("Low Task", Task.Priority.LOW, Task.TaskStatus.TODO, false);
        createAndPersistTask("Another High", Task.Priority.HIGH, Task.TaskStatus.TODO, false);

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters(null, Task.Priority.HIGH, null, pageable);

        assertEquals(2, page.getTotalElements());
    }

    @Test
    void searchTasks_shouldFilterByStatus() {
        createAndPersistTask("Todo Task", Task.Priority.MEDIUM, Task.TaskStatus.TODO, false);
        createAndPersistTask("Done Task", Task.Priority.MEDIUM, Task.TaskStatus.DONE, false);

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters(null, null, Task.TaskStatus.DONE, pageable);

        assertEquals(1, page.getTotalElements());
        assertEquals("Done Task", page.getContent().get(0).getTitle());
    }

    @Test
    void searchTasks_shouldCombineKeywordAndPriorityFilters() {
        createAndPersistTask("Important High", Task.Priority.HIGH, Task.TaskStatus.TODO, false);
        createAndPersistTask("Important Low", Task.Priority.LOW, Task.TaskStatus.TODO, false);
        createAndPersistTask("Other High", Task.Priority.HIGH, Task.TaskStatus.TODO, false);

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters("important", Task.Priority.HIGH, null, pageable);

        assertEquals(1, page.getTotalElements());
        assertEquals("Important High", page.getContent().get(0).getTitle());
    }

    @Test
    void searchTasks_shouldCombineAllFilters() {
        createAndPersistTask("Important High Todo", Task.Priority.HIGH, Task.TaskStatus.TODO, false);
        createAndPersistTask("Important High Done", Task.Priority.HIGH, Task.TaskStatus.DONE, false);
        createAndPersistTask("Important Low Todo", Task.Priority.LOW, Task.TaskStatus.TODO, false);

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters("important", Task.Priority.HIGH, Task.TaskStatus.TODO, pageable);

        assertEquals(1, page.getTotalElements());
        assertEquals("Important High Todo", page.getContent().get(0).getTitle());
    }

    // --- Pagination (M2-AC10, AC13) ---

    @Test
    void searchTasks_shouldSupportPagination() {
        for (int i = 1; i <= 7; i++) {
            createAndPersistTask("Task " + i);
        }

        Pageable firstPage = PageRequest.of(0, 3);
        Page<Task> page0 = taskRepository.findByFilters(null, null, null, firstPage);

        assertEquals(3, page0.getContent().size());
        assertEquals(7, page0.getTotalElements());
        assertEquals(3, page0.getTotalPages());

        Pageable secondPage = PageRequest.of(1, 3);
        Page<Task> page1 = taskRepository.findByFilters(null, null, null, secondPage);

        assertEquals(3, page1.getContent().size());
        assertEquals(1, page1.getNumber());
    }

    @Test
    void searchTasks_shouldSupportSorting() {
        createAndPersistTask("B Task");
        createAndPersistTask("A Task");
        createAndPersistTask("C Task");

        Pageable pageable = PageRequest.of(0, 20, Sort.by(Sort.Direction.DESC, "createdAt"));
        Page<Task> page = taskRepository.findByFilters(null, null, null, pageable);

        assertEquals(3, page.getTotalElements());
        // The last created should come first with DESC sort
        assertEquals("C Task", page.getContent().get(0).getTitle());
    }

    @Test
    void searchTasks_shouldReturnEmptyPageWhenNoMatch() {
        createAndPersistTask("Some Task");

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters("nonexistent", null, null, pageable);

        assertEquals(0, page.getTotalElements());
        assertTrue(page.getContent().isEmpty());
    }

    @Test
    void searchTasks_keywordShouldMatchPartialTitle() {
        createAndPersistTask("My Important Task");

        Pageable pageable = PageRequest.of(0, 20);
        Page<Task> page = taskRepository.findByFilters("import", null, null, pageable);

        assertEquals(1, page.getTotalElements(), "Partial keyword should match via LIKE");
    }

    // --- Soft delete does not affect findById from JpaRepository ---

    @Test
    void standardFindById_shouldStillReturnSoftDeletedTask() {
        Task saved = createAndPersistTask("Will Delete", Task.Priority.MEDIUM, Task.TaskStatus.TODO, true);

        Optional<Task> found = taskRepository.findById(saved.getId());

        assertTrue(found.isPresent(), "Standard findById should return soft-deleted tasks (use findByIdAndDeletedFalse for filtering)");
    }
}

