package com.taskflow.dto;

import com.taskflow.entity.Task;
import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

class TaskRequestTest {

    private static Validator validator;

    @BeforeAll
    static void setUpValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    @Test
    void shouldAcceptValidRequest() {
        TaskRequest request = new TaskRequest();
        request.setTitle("Valid Title");
        request.setDescription("A description");
        request.setPriority(Task.Priority.HIGH);

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        assertTrue(violations.isEmpty(), "Valid request should have no violations");
    }

    @Test
    void shouldAcceptRequestWithoutDescription() {
        TaskRequest request = new TaskRequest();
        request.setTitle("Title Only");

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasDescViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("description"));
        assertFalse(hasDescViolation, "Description is optional");
    }

    @Test
    void shouldAcceptRequestWithoutPriority() {
        TaskRequest request = new TaskRequest();
        request.setTitle("Title Only");

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasPriorityViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("priority"));
        assertFalse(hasPriorityViolation, "Priority is optional");
    }

    // --- Title validation ---

    @Test
    void shouldRejectNullTitle() {
        TaskRequest request = new TaskRequest();
        request.setTitle(null);

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertTrue(hasTitleViolation, "Null title should be rejected");
    }

    @Test
    void shouldRejectEmptyTitle() {
        TaskRequest request = new TaskRequest();
        request.setTitle("");

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertTrue(hasTitleViolation, "Empty title should be rejected");
    }

    @Test
    void shouldAcceptTitleWith1Character() {
        TaskRequest request = new TaskRequest();
        request.setTitle("A");

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertFalse(hasTitleViolation, "1-char title should be accepted");
    }

    @Test
    void shouldAcceptTitleWith200Characters() {
        TaskRequest request = new TaskRequest();
        request.setTitle("x".repeat(200));

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertFalse(hasTitleViolation, "200-char title should be accepted");
    }

    @Test
    void shouldRejectTitleWith201Characters() {
        TaskRequest request = new TaskRequest();
        request.setTitle("x".repeat(201));

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasTitleViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("title"));
        assertTrue(hasTitleViolation, "201-char title should be rejected");
    }

    // --- Description validation ---

    @Test
    void shouldAcceptDescriptionWith5000Characters() {
        TaskRequest request = new TaskRequest();
        request.setTitle("Valid");
        request.setDescription("d".repeat(5000));

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasDescViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("description"));
        assertFalse(hasDescViolation, "5000-char description should be accepted");
    }

    @Test
    void shouldRejectDescriptionWith5001Characters() {
        TaskRequest request = new TaskRequest();
        request.setTitle("Valid");
        request.setDescription("d".repeat(5001));

        Set<ConstraintViolation<TaskRequest>> violations = validator.validate(request);
        boolean hasDescViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("description"));
        assertTrue(hasDescViolation, "5001-char description should be rejected");
    }

    // --- Getter/Setter ---

    @Test
    void shouldGetAndSetAllFields() {
        TaskRequest request = new TaskRequest();
        request.setTitle("My Task");
        request.setDescription("My Desc");
        request.setPriority(Task.Priority.LOW);

        assertEquals("My Task", request.getTitle());
        assertEquals("My Desc", request.getDescription());
        assertEquals(Task.Priority.LOW, request.getPriority());
    }
}

