package com.taskflow.dto;

import com.taskflow.entity.Task;
import org.junit.jupiter.api.Test;

import java.time.LocalDateTime;

import static org.junit.jupiter.api.Assertions.*;

class TaskResponseTest {

    @Test
    void shouldGetAndSetAllFields() {
        TaskResponse response = new TaskResponse();
        LocalDateTime now = LocalDateTime.now();

        response.setId(1L);
        response.setTitle("Test Title");
        response.setDescription("Test Description");
        response.setPriority(Task.Priority.HIGH);
        response.setStatus(Task.TaskStatus.IN_PROGRESS);
        response.setCreatedBy(42L);
        response.setCreatedAt(now);
        response.setUpdatedAt(now.plusHours(1));

        assertEquals(1L, response.getId());
        assertEquals("Test Title", response.getTitle());
        assertEquals("Test Description", response.getDescription());
        assertEquals(Task.Priority.HIGH, response.getPriority());
        assertEquals(Task.TaskStatus.IN_PROGRESS, response.getStatus());
        assertEquals(42L, response.getCreatedBy());
        assertEquals(now, response.getCreatedAt());
        assertEquals(now.plusHours(1), response.getUpdatedAt());
    }

    @Test
    void shouldAllowNullDescription() {
        TaskResponse response = new TaskResponse();
        response.setDescription(null);
        assertNull(response.getDescription());
    }

    @Test
    void shouldAllowNullUpdatedAt() {
        TaskResponse response = new TaskResponse();
        response.setUpdatedAt(null);
        assertNull(response.getUpdatedAt());
    }

    @Test
    void shouldMatchContractFields() {
        // CONTRACT: TaskResponse fields = id:long, title:string, description:string?,
        // priority:enum(HIGH|MEDIUM|LOW), status:enum(TODO|IN_PROGRESS|DONE|CLOSED),
        // createdBy:long, createdAt:ISO8601, updatedAt:ISO8601?
        TaskResponse response = new TaskResponse();
        LocalDateTime now = LocalDateTime.now();

        response.setId(100L);
        response.setTitle("Contract Task");
        response.setDescription(null);
        response.setPriority(Task.Priority.MEDIUM);
        response.setStatus(Task.TaskStatus.TODO);
        response.setCreatedBy(5L);
        response.setCreatedAt(now);
        response.setUpdatedAt(null);

        assertEquals(100L, response.getId());
        assertEquals("Contract Task", response.getTitle());
        assertNull(response.getDescription());
        assertEquals(Task.Priority.MEDIUM, response.getPriority());
        assertEquals(Task.TaskStatus.TODO, response.getStatus());
        assertEquals(5L, response.getCreatedBy());
        assertNotNull(response.getCreatedAt());
        assertNull(response.getUpdatedAt());
    }
}

